arguments.command:
cd /tmp/symbols
# It has a .gnu_debuglink section - let's see what it points to
readelf -p .gnu_debuglink libmonosgen-2.0.so 2>/dev/null

# Also let's check dynamic symbols for our addresses
# The offsets from the tombstone: 0x222098, 0x2241ac, 0x1abc80, 0x1abd14, 0x16dfa4, 0x16db6c, 0x16de04
readelf --dyn-syms libmonosgen-2.0.so 2>/dev/null | sort -k2 | awk '$2 != ""' | grep -v "^$" > dynsyms.txt

# Use a python script to find symbols for each address
python3 << 'EOF'
import subprocess, re

addresses = [0x222098, 0x2241ac, 0x1abc80, 0x1abd14, 0x16dfa4, 0x16db6c, 0x16de04]

# Parse dynamic symbols
syms = []
with open('dynsyms.txt') as f:
    for line in f:
        parts = line.split()
        if len(parts) >= 8:
            try:
                addr = int(parts[1], 16)
                size = int(parts[2])
                name = parts[7] if len(parts) > 7 else ""
                if addr > 0 and name:
                    syms.append((addr, size, name))
            except (ValueError, IndexError):
                pass

syms.sort(key=lambda x: x[0])

for target in addresses:
    found = None
    for addr, size, name in syms:
        if addr <= target < addr + size:
            found = (name, target - addr)
            break
        # Also check if it's the closest symbol before
    if not found:
        # Find closest symbol before target
        best = None
        for addr, size, name in syms:
            if addr <= target:
                best = (name, target - addr, addr)
        if best:
            found = (best[0], best[1])

    if found:
        print(f"  0x{target:08x}: {found[0]}+0x{found[1]:x}")
    else:
        print(f"  0x{target:08x}: ???")
EOF

