arguments.command:
cd /tmp/symbols
# Let me get better symbol resolution - the offsets are too large, meaning these are approximate.
# Let me get the full symbol names and find the actual containing function for each address
python3 << 'EOF'
import subprocess, re

addresses = [0x222098, 0x2241ac, 0x1abc80, 0x1abd14, 0x16dfa4, 0x16db6c, 0x16de04]

# Parse dynamic symbols more carefully
syms = []
result = subprocess.run(['readelf', '--dyn-syms', '-W', 'libmonosgen-2.0.so'], capture_output=True, text=True)
for line in result.stdout.split('\n'):
    parts = line.split()
    if len(parts) >= 8:
        try:
            addr = int(parts[1], 16)
            size = int(parts[2])
            typ = parts[3]
            name = parts[7]
            if addr > 0 and typ == "FUNC" and size > 0:
                syms.append((addr, size, name))
        except (ValueError, IndexError):
            pass

syms.sort(key=lambda x: x[0])

for target in addresses:
    # Find the function that contains this address
    found = None
    for addr, size, name in syms:
        if addr <= target < addr + size:
            found = (name, target - addr)
            break

    if not found:
        # Find closest function before target
        best = None
        for addr, size, name in syms:
            if addr <= target:
                best = (name, target - addr)
        found = best

    if found:
        print(f"  0x{target:08x}: {found[0]}+0x{found[1]:x}")
    else:
        print(f"  0x{target:08x}: <unknown>")
EOF

